import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';
import { nguoiDungAPI } from '../services/api';
import useAuthStore from '../store/authStore';
import './HoSoCaNhan.css';

export default function HoSoCaNhan() {
  const { user, layThongTinToi } = useAuthStore();
  const [editing, setEditing] = useState(false);
  const [form, setForm] = useState({ hoTen: user?.hoTen || '', soDienThoai: user?.soDienThoai || '' });
  const [saving, setSaving] = useState(false);
  const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);

  const handleSave = async () => {
    setSaving(true);
    try {
      await nguoiDungAPI.capNhat(form);
      await layThongTinToi();
      toast.success('Cập nhật thành công!');
      setEditing(false);
    } catch { toast.error('Cập nhật thất bại'); }
    setSaving(false);
  };

  const handleAvatarChange = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const fd = new FormData();
    fd.append('file', file);
    try {
      await nguoiDungAPI.uploadAvatar(fd);
      await layThongTinToi();
      toast.success('Cập nhật ảnh đại diện thành công!');
    } catch { toast.error('Upload thất bại'); }
  };

  if (!user) return <div className="spinner" />;

  return (
    <div className="container page-wrapper">
      <div className="hoso-layout">
        {/* Profile card */}
        <div className="card profile-card">
          <div className="card-body" style={{ textAlign:'center' }}>
            <div className="avatar-upload">
              <img
                src={user.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(user.hoTen)}&background=FF6B35&color=fff&size=120`}
                className="avatar avatar-xl" alt="" />
              <label htmlFor="avatar-input" className="avatar-edit-btn" title="Đổi ảnh">✏️</label>
              <input id="avatar-input" type="file" accept="image/*" hidden onChange={handleAvatarChange} />
            </div>
            <h2 style={{ marginTop: 16, fontWeight: 800 }}>{user.hoTen}</h2>
            {user.xacThuc
              ? <span className="badge badge-success" style={{ marginTop: 8 }}>✅ Đã xác thực CCCD</span>
              : <Link to="/xac-thuc" className="badge badge-warning" style={{ marginTop: 8, cursor:'pointer', textDecoration:'none' }}>⚠️ Chưa xác thực — Xác thực ngay</Link>
            }
            {user.diemDanhGia && (
              <div className="stars" style={{ marginTop: 12 }}>
                {'★'.repeat(Math.round(user.diemDanhGia))}{'☆'.repeat(5 - Math.round(user.diemDanhGia))}
                <span style={{ fontSize: 14, color:'var(--text-muted)', marginLeft: 6 }}>{user.diemDanhGia?.toFixed(1)}</span>
              </div>
            )}
            <div style={{ marginTop: 20, padding: '16px 0', borderTop:'1px solid var(--border)' }}>
              <div style={{ fontSize: 13, color:'var(--text-muted)' }}>Số dư ví</div>
              <div style={{ fontSize: 24, fontWeight: 800, color:'var(--primary)' }}>{fmt(user.soDuVi)}</div>
              <Link to="/thanh-toan" className="btn btn-outline btn-sm" style={{ marginTop: 8 }}>Nạp tiền</Link>
            </div>
          </div>
        </div>

        {/* Info */}
        <div>
          <div className="card">
            <div className="card-header" style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <span>📋 Thông tin cá nhân</span>
              {!editing
                ? <button className="btn btn-outline btn-sm" onClick={() => setEditing(true)}>✏️ Chỉnh sửa</button>
                : <div style={{ display:'flex', gap:8 }}>
                    <button className="btn btn-primary btn-sm" onClick={handleSave} disabled={saving}>{saving ? '⏳' : '💾 Lưu'}</button>
                    <button className="btn btn-secondary btn-sm" onClick={() => setEditing(false)}>Hủy</button>
                  </div>
              }
            </div>
            <div className="card-body">
              {editing ? (
                <>
                  <div className="form-group">
                    <label className="form-label">Họ và tên</label>
                    <input className="form-control" value={form.hoTen} onChange={e => setForm(f => ({...f, hoTen: e.target.value}))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Số điện thoại</label>
                    <input className="form-control" value={form.soDienThoai} onChange={e => setForm(f => ({...f, soDienThoai: e.target.value}))} />
                  </div>
                </>
              ) : (
                <div>
                  {[
                    ['👤 Họ tên', user.hoTen],
                    ['📧 Email', user.email],
                    ['📱 Điện thoại', user.soDienThoai || 'Chưa cập nhật'],
                    ['📅 Ngày tham gia', user.ngayTao ? new Date(user.ngayTao).toLocaleDateString('vi-VN') : ''],
                  ].map(([label, val]) => (
                    <div key={label} className="info-row">
                      <span style={{ color:'var(--text-muted)' }}>{label}</span>
                      <strong>{val}</strong>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="card" style={{ marginTop: 20 }}>
            <div className="card-header">⚡ Hành động nhanh</div>
            <div className="card-body">
              <div className="quick-actions">
                {[
                  ['/quan-ly-phong', '🏠', 'Quản lý phòng'],
                  ['/yeu-cau', '📋', 'Yêu cầu của tôi'],
                  ['/thanh-toan', '💳', 'Thanh toán'],
                  ['/tam-tru', '📄', 'Phiếu tạm trú'],
                  ['/danh-gia', '⭐', 'Đánh giá'],
                  ['/xac-thuc', '🔐', 'Xác thực CCCD'],
                ].map(([to, icon, label]) => (
                  <Link key={to} to={to} className="quick-action-btn">
                    <span>{icon}</span><span>{label}</span>
                  </Link>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
